export const Navbar = () => {
    const { user, authDataLoading } = useAuth();
    const { language, setLanguage, languages } = useLanguage();
    const navigate = useNavigate();
    const location = useLocation();
    const profileLink = user ? `/profile/${user.username}` : "/auth";
    const { primaryColor, secondaryColor } = useTheme();

    const isActive = (link) => location.pathname === link;
    return (
        <div className="flex items-center h-full w-full px-4 gap-4">
            <div className="h-full">
                <Logo />
            </div>

            <div className="flex-1 flex justify-between">
                {/* Left Navigation */}
                <div className="flex gap-4">
                    {leftNavItems.map((item) => (
                        <button
                            key={item.label}
                            onClick={() => item.link && navigate(item.link)}
                            title={item.label}
                            className="cursor-pointer transition-opacity hover:opacity-75"
                            style={{
                                color: isActive(item.link)
                                    ? primaryColor
                                    : secondaryColor,
                            }}
                        >
                            {item.icon}
                        </button>
                    ))}
                </div>

                {/* Right Navigation */}
                <div className="flex items-center gap-4">
                                        <select
                        value={language}
                        onChange={(e) => setLanguage(e.target.value)}
                        className="outline-none rounded-md px-2 py-1 text-sm cursor-pointer border"
                        style={{
                            color: secondaryColor,
                            borderColor: secondaryColor,
                            background: "transparent",
                        }}
                    >
                        {languages.map((lang) => (
                            <option
                                key={lang}
                                value={lang}
                                style={{ color: "#000" }}
                            >
                                {lang}
                            </option>
                        ))}
                    </select>
                    {rightNavItems.map((item) => {
                        const link =
                            item.label === "Profile"
                                ? profileLink
                                : item.link;

                        return (
                            <button
                                key={item.label}
                                onClick={() => link && navigate(link)}
                                title={item.label}
                                className="cursor-pointer transition-opacity hover:opacity-75"
                                style={{
                                    color:
                                        location.pathname === link
                                            ? primaryColor
                                            : secondaryColor,
                                }}
                            >
                                {item.icon}
                            </button>
                        );
                    })}


                </div>
            </div>
        </div>
    );
};